+//------------------------------------------------------------------------------
+int ngap_gNB_ue_capabilities(instance_t instance, ngap_ue_cap_info_ind_t *ue_cap_info_ind_p)
+//------------------------------------------------------------------------------
+{
+  ngap_gNB_instance_t          *ngap_gNB_instance_p;
+  struct ngap_gNB_ue_context_s *ue_context_p;
