+            (uint64_t)ue_context_p->amf_ue_ngap_id,
+            pdusession_release_resp_p->nb_of_pdusessions_released);
+
+  ASN_STRUCT_FREE_CONTENTS_ONLY(asn_DEF_NGAP_NGAP_PDU, &pdu);
+  return 0;
+}
