+/**
+ * @brief F1AP Setup Failure deep copy
+ */
+f1ap_setup_failure_t cp_f1ap_setup_failure(const f1ap_setup_failure_t *msg)
+{
+  f1ap_setup_failure_t cp = {0};
+  /* transaction_id */
+  cp.transaction_id = msg->transaction_id;
+  return cp;
+}
