+    ie->id = NGAP_ProtocolIE_ID_id_UERadioCapability;
+    ie->criticality = NGAP_Criticality_ignore;
+    ie->value.present = NGAP_UERadioCapabilityInfoIndicationIEs__value_PR_UERadioCapability;
